import{_ as s,c as a,o as p,a4 as n}from"./chunks/framework.CC18aqI2.js";const b=JSON.parse('{"title":"简易个人博客搭建(初级版)","description":"","frontmatter":{"prev":false,"next":{"text":"简易博客搭建(高级版)","link":"article/tutorial/buildBlog/hardBuild"}},"headers":[],"relativePath":"article/tutorial/buildBlog/easyBuild.md","filePath":"article/tutorial/buildBlog/easyBuild.md","lastUpdated":null}'),t={name:"article/tutorial/buildBlog/easyBuild.md"},e=n(`<h1 id="简易个人博客搭建-初级版" tabindex="-1">简易个人博客搭建(初级版) <a class="header-anchor" href="#简易个人博客搭建-初级版" aria-label="Permalink to &quot;简易个人博客搭建(初级版)&quot;">​</a></h1><h2 id="📝前言" tabindex="-1">📝前言 <a class="header-anchor" href="#📝前言" aria-label="Permalink to &quot;📝前言&quot;">​</a></h2><p>这篇文章会非常详细地说明如何从零开始搭建一个和本站一样的简易个人博客🤨</p><p>无论你是零基础的小白，还是有编程基础的程序员，都可以轻松且几乎零成本地搭建个人博客😮</p><p>本站虽小，但五脏俱全，完全可以实现基本的博客功能😋</p><p>最重要的是，它不需要部署在服务器上，完全免费😍</p><p>本教程是多个教程(在&quot;参考&quot;部分)的综合版本，在原本教程的基础上进行了缝合和优化😎</p><p>这是初级版教程，如果你想学复杂的网站配置得看高级版教程(还在编写文档中)或者点下面👇</p><p><a href="https://www.bilibili.com/video/BV1XW4y1w7bc" target="_blank" rel="noreferrer">看建站教学视频点我</a></p><p>好了，废话不多说，马上开始我们的搭建博客之旅吧🏃‍♂️</p><h2 id="🔧准备工作" tabindex="-1">🔧准备工作 <a class="header-anchor" href="#🔧准备工作" aria-label="Permalink to &quot;🔧准备工作&quot;">​</a></h2><p>俗话说，巧妇难成无米之炊。要想完整地搭建这样的一个博客，你需要提前进行如下准备:</p><ul><li>一个github账号</li><li>git</li><li>VS Code</li><li>npm和Node.js</li><li>yarn</li><li>Typora(或者其它md格式的文档编辑器)</li></ul><p>除了Typora，其它都是必备的，如果没有合适的编程环境，就无法搭建这个博客了😭</p><p>当然，如果你没有，也不要担心。作为一篇保姆级教程，自然也会教你怎么做准备工作啦❤️</p><p><strong>github注册</strong></p><p>这个就没什么好说的了，只要用点魔法🧙‍♂️，正常登录网站注册账号即可。Github有时候不用魔法也能访问，就是不太稳定……</p><p>网址👉<a href="https://github.com/" target="_blank" rel="noreferrer">Github</a></p><p><strong>git</strong></p><p>这个很重要，部署上线网站需要用到git。git的下载也很简单，进入git的官网直接选择你操作系统对应的版本，然后无脑dowload下载安装即可。附上下载地址:<a href="https://git-scm.com/downloads" target="_blank" rel="noreferrer">Git</a></p><p><strong>VS Code</strong></p><p>一个很著名的代码编辑器，因为这是一个前端的网页项目，网页的编写配置都需要用到这款主流的代码编辑器</p><p>也是根据操作系统选择对应的版本无脑dowload下载安装即可。附上下载地址:<a href="https://code.visualstudio.com/" target="_blank" rel="noreferrer">VS Code</a></p><p><strong>npm和Node.js</strong></p><p>这个东西的下载和配置很麻烦。因为这篇教程主要是关于博客搭建的，就不在这里过多赘述node的下载安装配置了，可以参考下面的这篇文章学习，写得相当详细👇</p><p><a href="https://blog.csdn.net/qq_42006801/article/details/124830995" target="_blank" rel="noreferrer">node安装配置教程</a></p><p>⚠️Node.js最好要安装18及以上的版本！</p><p><strong>Yarn</strong></p><p>Yarn是一个常见的包管理工具，安装Node环境后使用npm命令或者安装yarn</p><p>yarn全局安装命令(在cmd命令行窗口中输入)：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>npm i yarn -g</span></span></code></pre></div><p>如果不知道如何安装Yarn，可以参考下面这篇文章👇</p><p><a href="https://yarn.nodejs.cn/en/docs/install#windows-stable" target="_blank" rel="noreferrer">Yarn安装教程中文网</a></p><p><strong>Typora</strong></p><p>这个文档编辑器不是必备的，也可以用一些其他的软件平替或者直接在VS Code里面编写，只是作者认为这个软件很好用，有强大的文档编辑功能，支持markdown格式</p><p>但是，官方的Typora是要收费的，不过作者有它的破解版，如果你需要的话，可以添加作者的联系方式(点击首页的&quot;关于Itai&quot;按钮)，无偿提供😎</p><p>如果你确定已经做好了上述准备工作，那么我们就可以正式开始搭建博客了✌️</p><h2 id="💡项目初始化" tabindex="-1">💡项目初始化 <a class="header-anchor" href="#💡项目初始化" aria-label="Permalink to &quot;💡项目初始化&quot;">​</a></h2><p>在任意磁盘下为我们的博客代码单独创建一个新的文件夹，文件夹名字中不要带中文和空格(以D盘myblog为例)</p><p>然后，在文件管理器的上面输入cmd，如下图</p><p><img src="https://itai-blog.oss-cn-hangzhou.aliyuncs.com/1.png" alt="1"></p><p>然后摁下回车，就会进入命令行窗口，然后输入以下命令:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>yarn add -D vitepress</span></span></code></pre></div><p>系统就会自动联网下载vitepress的环境。如果全程没有报错(比如出现红色的&quot;Error&quot;)，并且多出了如下文件:</p><p><img src="https://itai-blog.oss-cn-hangzhou.aliyuncs.com/2.png" alt="2"></p><p>说明vitepress的环境正常安装好了</p><p>然后我们用VS Code打开这个文件，在VS Code最上面的导航栏中有三个点，里面有一个&quot;终端&quot;选项，然后新建终端，就可以在VS Code里面使用命令行窗口，然后在命令行窗口中输入:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>npx vitepress init</span></span></code></pre></div><p>然后就会要你来回答几个问题，问题如下:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌  Welcome to VitePress!</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>◇  Where should VitePress initialize the config?</span></span>
<span class="line"><span>│  ./</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>◇  Site title:</span></span>
<span class="line"><span>│  My Awesome Project</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>◇  Site description:</span></span>
<span class="line"><span>│  A VitePress Site</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>◇  Theme:</span></span>
<span class="line"><span>│  Default Theme + Customization</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>◇  Use TypeScript for config and theme files?</span></span>
<span class="line"><span>│  No</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>◇  Add VitePress npm scripts to package.json?</span></span>
<span class="line"><span>│  Yes</span></span></code></pre></div><p>按照上面的选，如果跳出了提示:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>└  Done! Now run npm run docs:dev and start writing.</span></span></code></pre></div><p>还发现，多出来了一个叫做&quot;.vitepress&quot;的文件夹以及一些扩展名为&quot;.md&quot;的文件，说明没问题👌</p><p>最后，你还需要创建一个名叫&quot;docs&quot;的文件夹(⚠️必须叫这个名字！！！)</p><p>然后把&quot;.vitepress&quot;文件夹和其它三个文件扩展名为&quot;.md&quot;的文件(⚠️尤其是&quot;index.md&quot;)放入新创建的docs文件夹中</p><p>完成后的目录be like:</p><p><img src="https://itai-blog.oss-cn-hangzhou.aliyuncs.com/3.png" alt="3"></p><div class="warning custom-block github-alert"><p class="custom-block-title">WARNING</p><p></p><p>注意，node_modules这个文件夹自始至终不要去动它！</p></div><p>到此，项目初始化部分就彻底完成了🎉</p><h2 id="✨自定义网站配置" tabindex="-1">✨自定义网站配置 <a class="header-anchor" href="#✨自定义网站配置" aria-label="Permalink to &quot;✨自定义网站配置&quot;">​</a></h2><p>初始化完成之后，其实vitepress官方就已经给我们准备好了一个模板网页，但是内容都是模板化的，我们需要进行个性化配置，让网页能变成我们喜欢的模样😋</p><h3 id="🌸美化主页" tabindex="-1">🌸美化主页 <a class="header-anchor" href="#🌸美化主页" aria-label="Permalink to &quot;🌸美化主页&quot;">​</a></h3><p>在开始美化主页之前，我们先运行一下程序，看看vitepress提供的默认的网站大概是长什么样子的</p><p>在VS Code的终端中输入如下命令:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>yarn vitepress dev docs</span></span></code></pre></div><p>运行成功的话，你会在终端中看到如下文字:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PS D:\\blog&gt; yarn vitepress dev docs</span></span>
<span class="line"><span>yarn run v1.22.22</span></span>
<span class="line"><span>warning package.json: No license field</span></span>
<span class="line"><span>$ D:\\blog\\node_modules\\.bin\\vitepress dev docs</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  vitepress v1.2.3</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  ➜  Local:   http://localhost:5173/</span></span>
<span class="line"><span>  ➜  Network: use --host to expose</span></span>
<span class="line"><span>  ➜  press h to show help</span></span></code></pre></div><p>你会发现那个网址是蓝色文字，说明可以点击。摁住Ctrl，并鼠标左键点击那个网址，就会打开你电脑默认的浏览器</p><p>打开浏览器后的网站效果如下图，有9个地方可以自定义。接下来就讲一下这9个地方怎么自定义的。</p><p><img src="https://itai-blog.oss-cn-hangzhou.aliyuncs.com/4.png" alt="4"></p><p><img src="https://itai-blog.oss-cn-hangzhou.aliyuncs.com/5.png" alt="5"></p><p>9这个注脚是直接配置footer，在<code>config.mjs defineConfig themeConfig</code>下面配置就可以了</p><p><img src="https://itai-blog.oss-cn-hangzhou.aliyuncs.com/6.png" alt="6"></p><p>注脚有可有无，在网站的最底部，内容也是随意指定的(双引号里面)，输入自己喜欢的内容就行</p><p>2-6是在index.md文件中自定义的。简单介绍一下对应关系</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>name&lt;==&gt;2 text&lt;==&gt;3 tagline&lt;==&gt;4 actions&lt;==&gt;5 features&lt;==&gt;6</span></span></code></pre></div><p>需要说明的是，对于5这两个按钮，是可以跳转的，<strong>link指定路径</strong>，比如/api-example就是在docs目录下找api-example.md这个文件。当然，这个目录是可以比较灵活地指定的，也可以指定docs目录下一些文件夹中的文件</p><p>还有theme属性是vitepress官方给定的按钮样式，好像只有brand(亮蓝色按钮)和alt(灰色按钮)两种</p><p>如果说，你想要删除某个按钮或者再添加按钮，删除(或者添加)如下这个部分即可:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>- theme:</span></span>
<span class="line"><span>  text:</span></span>
<span class="line"><span>  link:</span></span></code></pre></div><p>这三个属性代表一个按钮，是一个整体，以&quot;-&quot;为标识，当然你也可以不给属性赋值</p><p><img src="https://itai-blog.oss-cn-hangzhou.aliyuncs.com/7.png" alt="7"></p><p>修改后的页面如下：</p><p><img src="https://itai-blog.oss-cn-hangzhou.aliyuncs.com/8.png" alt="8"></p><p>1、7、8这三个配置是在config.mjs中配置的</p><p>其中，title对应1，nav对应7，socialLinks对应8。description是SEO要用的，我们不用关注。</p><p><img src="https://itai-blog.oss-cn-hangzhou.aliyuncs.com/9.png" alt="9"></p><p>特别的，nav中的text代表导航栏中的文字内容，link表示点击了导航栏会跳转到哪里去，比如&quot;/&quot;就代表首页</p><p>socialLinks是网站右上角的一个社交网站的图标(默认是github)，这个也可以自己灵活设置，参考进阶教程</p><p>设置完以后，大概效果就是:</p><p><img src="https://itai-blog.oss-cn-hangzhou.aliyuncs.com/10.png" alt="10"></p><p>到这里，主页就完成了初步美化🎉</p><h3 id="🤩主页扩展" tabindex="-1">🤩主页扩展 <a class="header-anchor" href="#🤩主页扩展" aria-label="Permalink to &quot;🤩主页扩展&quot;">​</a></h3><p>不过，虽然主页已经有些个性化的因素了，但是标题的右侧空荡荡的，得加点什么才好看🤔</p><p>🤩对了，就是一张漂亮的图片🤩</p><p>温馨提示:最好使用透明背景的图片，如果你不知道怎么把自己喜欢的图片变成透明背景，可以用下面这个网站</p><p><a href="https://www.quzuotu.com/home" target="_blank" rel="noreferrer">趣图网</a>👈一个完全免费的图片处理网站，上传本地图片就能自动抠图，亲测靠谱，不是打广告😎</p><p>当然，如果你自己没有图片，可以去这个网站找👉<a href="https://www.iconfont.cn/" target="_blank" rel="noreferrer">阿里巴巴矢量图形库</a>👈也是完全免费下载海量透明背景图片</p><p>搞定图片之后，在docs目录下面创建一个叫&quot;public&quot;(⚠️必须叫这个名字)的文件夹，然后把图片放进去，取名为background.文件扩展名(也可以不取这个名字，但是这样规范)，然后在index.md文件下插入下图属性:</p><p><img src="https://itai-blog.oss-cn-hangzhou.aliyuncs.com/11.png" alt="11"></p><p>src代表图片的路径，格式为&quot;/文件名.扩展名&quot;文件名和扩展名写你自己的文件，不一定是background</p><p>最后美化的效果如图：</p><p><img src="https://itai-blog.oss-cn-hangzhou.aliyuncs.com/12.png" alt="12"></p><p>这个图片放进去后默认会有一个渐变背景色，这个可以调，参见高级版教程</p><p>可以看到，网页是完全支持简单表情的👍</p><p>还有两个配置，一个是网页图标，一个是博客的logo</p><p>这两个的配置也非常简单，找到&quot;.vitepress&quot;文件夹下面的&quot;config.mjs&quot;文件，照着下面配置:</p><p><img src="https://itai-blog.oss-cn-hangzhou.aliyuncs.com/13.png" alt="13"></p><p>head控制了网页标签的图标，head的href属性表示这个文件的路径和文件名，这个文件必须在public下面才能这样写</p><p>head修改之后效果如下:</p><p><img src="https://itai-blog.oss-cn-hangzhou.aliyuncs.com/14.png" alt="14"></p><p>logo控制了这个博客的logo，logo的图片文件也必须放在public目录下面才行。修改之后效果如下:</p><p><img src="https://itai-blog.oss-cn-hangzhou.aliyuncs.com/15.png" alt="15"></p><p>就是在网页左上角的文字左边加了一个网站的logo</p><p>顺带一提，网页右上角，github图标的左边还有个开关，这个是切换网页主题的，点击一下就可以变成夜晚主题</p><p>至此，主页扩展部分也就做好啦🎉</p><h2 id="✏️文章编写与上传" tabindex="-1">✏️文章编写与上传 <a class="header-anchor" href="#✏️文章编写与上传" aria-label="Permalink to &quot;✏️文章编写与上传&quot;">​</a></h2><div class="warning custom-block github-alert"><p class="custom-block-title">WARNING</p><p></p><p>这部分规则会有点复杂，请耐心仔细地阅读</p></div><p>这个网站是没有后台管理界面的，因此如果需要把博客文章放到网站里面都需要自己手动配置</p><p><img src="https://itai-blog.oss-cn-hangzhou.aliyuncs.com/8.png" alt="8"></p><p>以这个主页为例，比如说我想实现点击&quot;第一个示例按钮&quot;之后跳转到某个自己写的博客文章</p><p>首先，我们得在配置文件里给这个按钮指定一个跳转网址路径，而这个网址路径一般来说和文件相对于docs的相对路径是要保持一致的(其实可以不一致，不过为了规范和便于管理，还是一致好)，这是什么意思呢？我举例说明</p><p>以我自己博客的文件放置为例，如下</p><p><img src="https://itai-blog.oss-cn-hangzhou.aliyuncs.com/16.png" alt="16"></p><p>我要点击主页的按钮后，去显示&quot;docs/about/aboutMe/index.md&quot;这个文件的内容，那么可以知道，index.md这个文件相对于docs这个目录的相对路径就是&quot;/about/aboutMe/index.md&quot;</p><p>⚠️注意这里是相对于docs的相对路径而不是相对于根目录的相对路径，你想要映射的文件夹必须放在docs目录下面</p><p>那么，根据规范，这个跳转地址我们就应该写&quot;/about/aboutMe&quot;</p><p>这样就可以去映射到&quot;docs/about/aboutMe&quot;这个文件夹下面的所有md文件了(不单单只映射index.md这个文件)</p><p>⚠️需要特别强调的是，这个index.md文件，只要你这个文件夹是被跳转路径所映射的，那么这个文件夹下面就必须有index.md这个文件，否则的话，无论文件夹下有无其它的文件，都会直接报404，丢失页面，这是框架的规定</p><p>而且默认情况下，如果你映射到&quot;docs/about/aboutMe&quot;这个文件夹，跳转之后默认就是显示index.md这个文件的内容</p><p>根据如上规则确定好我们要映射到哪个文件之后，我们在docs文件夹下面的index.md中去配置这个跳转路径:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  actions:</span></span>
<span class="line"><span>    - theme: alt</span></span>
<span class="line"><span>      text: 第一个示例</span></span>
<span class="line"><span>      link: /about/aboutMe</span></span></code></pre></div><p>这个配置在&quot;美化主页&quot;部分有说明，link就是代表跳转的地址</p><p>这样配置之后，就可以实现点击按钮，然后跳转页面并显示index.md文件下的内容了</p><p>如果说在&quot;docs/about/aboutMe&quot;这个文件下，还有一个非index.md文件，以&quot;hello.md&quot;为例，而你想跳转到这个文件，那么只要把路径改成&quot;link: /about/aboutMe/hello&quot;即可</p><p>⚠️路径中不要写扩展名，比如&quot;link: /about/aboutMe/hello.md&quot;❌</p><p>⚠️index.md这个文件比较特殊，想映射到这个文件不需要写成&quot;/about/aboutMe/index&quot;，因为index.md是默认的</p><p>⚠️文件名字中最好不要带中文和空格以及一些奇奇怪怪的字符，老老实实用英文取名字，否则出bug后果自负</p><p>如果你能认真看到这里，这个文件映射基本上就能掌握了，恭喜🎉</p><p>但是这只是初级版的文件上传教程，如果想要深入了解关于文件编写的内容，请看高级版教程</p><h2 id="📦打包部署" tabindex="-1">📦打包部署 <a class="header-anchor" href="#📦打包部署" aria-label="Permalink to &quot;📦打包部署&quot;">​</a></h2><p>对于这部分，就要特别鸣谢Ec3o的博客教程了，因为他的教程是最简单的，而且十分优雅😎</p><p>下面我就直接在Ec3o博客教程的基础上进行进一步阐述</p><p>首先，访问Ec3o的一个已经部署好的仓库Repo，仓库地址👉<a href="https://github.com/Ec3o/Ec3o.github.io" target="_blank" rel="noreferrer">Ec3o的仓库</a>👈，界面如下</p><p><img src="https://itai-blog.oss-cn-hangzhou.aliyuncs.com/17.png" alt="17"></p><p>点击右上角的Fork，把这个代码白嫖到自己的仓库，仓库取名为&quot;自己的账号名.github.io&quot;，其它配置默认即可</p><p>创建好仓库之后，回到VS Code中，在根目录(不是docs目录)下面创建一个文件，名字叫做&quot;deploy.sh&quot;</p><p>⚠️这个文件名字和文件扩展名必须保持一致，别乱改</p><p>然后在文件中复制粘贴下面这串代码，制作一个自动部署脚本:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>#!/usr/bin/env sh</span></span>
<span class="line"><span> </span></span>
<span class="line"><span># 忽略错误</span></span>
<span class="line"><span>set -e  #有错误抛出错误</span></span>
<span class="line"><span> </span></span>
<span class="line"><span># 构建</span></span>
<span class="line"><span>yarn run docs:build  #然后执行打包命令</span></span>
<span class="line"><span> </span></span>
<span class="line"><span># 进入待发布的目录</span></span>
<span class="line"><span>cd docs/.vitepress/dist  #进到dist目录</span></span>
<span class="line"><span> </span></span>
<span class="line"><span>git init  #执行这些git命令</span></span>
<span class="line"><span>git add -A</span></span>
<span class="line"><span>git commit -m &#39;deploy&#39;</span></span>
<span class="line"><span> </span></span>
<span class="line"><span>git push -f https://github.com/Ec3o/Ec3o.github.io.git master:gh-pages  #提交到这个分支</span></span>
<span class="line"><span> </span></span>
<span class="line"><span>cd -</span></span>
<span class="line"><span> </span></span>
<span class="line"><span>rm -rf docs/.vitepress/dist  #删除dist文件夹</span></span></code></pre></div><p>⚠特别注意，上面脚本中的<code>https://github.com/Ec3o/Ec3o.github.io.git master:gh-pages</code>千万别照抄，其中的&quot;Ec3o&quot;都换成你自己的github账号名字，比如我的github账号叫做&quot;Itai&quot;的话，路径就改成:</p><p><code>https://github.com/Itai/Itai.github.io.git master:gh-pages</code></p><p>保存之后，进入根目录下面的&quot;package.json&quot;文件，然后你会在其中找到一个&quot;scripts&quot;字段，把这个字段改成:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;scripts&quot;: {</span></span>
<span class="line"><span>    &quot;deploy&quot;:&quot;bash deploy.sh&quot;,</span></span>
<span class="line"><span>    &quot;docs:dev&quot;: &quot;vitepress dev docs&quot;,</span></span>
<span class="line"><span>    &quot;docs:build&quot;: &quot;vitepress build docs&quot;,</span></span>
<span class="line"><span>    &quot;docs:serve&quot;: &quot;vitepress serve docs&quot;</span></span>
<span class="line"><span>  },</span></span></code></pre></div><p>其它不动保持默认，然后，打开Git Bash(下载Git自带的)，这个时候要注意:</p><p>⚠刚打开是在一个默认的文件路径下，但是我们得在放网站源码的文件下执行命令</p><p>所以，先在命令行窗口中输入</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cd 存放网站源码的文件的绝对路径</span></span></code></pre></div><p>确定到正确目录下之后，再输入如下命令部署:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>yarn run deploy</span></span></code></pre></div><p>⚠这条命令要想正常执行必须完成上面的修改&quot;package.json&quot;文件</p><p>然后git就会自动帮你把代码push到github上面，非常简单且优雅</p><p>默认情况下，如果你没有自己绑定域名，且你完全按照本教程的规范做下来，那么你的博客的网址就是:</p><p>&quot;<a href="https://xn--github-on9iq72axf4605afb8b.github.io/" target="_blank" rel="noreferrer">https://你的github账号名.github.io/</a>&quot;</p><p>这样的话，无需服务器也能搭建一个自己的博客网站，而且别人也能访问哦😎</p><p>顺带一提，那个运行脚本千万别删掉，因为如果你之后要修改网站上的内容，你要先在本地修改对应的内容，然后再重新依照上述方法把本地的代码push到github上面，不push的话你的站点内容不会发生变化，只是在本地修改，访问你网站的人是看不到你本地的修改的哦</p><p>这只是一个基础的搭建教学，其实这个网站还有很多可自己去配置的地方，不过就需要你懂一些前端知识了</p><p>具体怎么配置，请参见高级教程(暂时还没写好)</p><p>🎉等待一会，等源码完全上传成功之后，你的网站就搭建好并且部署成功啦🎉</p><h2 id="📖参考" tabindex="-1">📖参考 <a class="header-anchor" href="#📖参考" aria-label="Permalink to &quot;📖参考&quot;">​</a></h2><p>vitepress官方教程:<a href="https://vitepress.dev/zh/guide/getting-started" target="_blank" rel="noreferrer">vitepress官方教程</a></p><p>Ec3o的博客教程:<a href="https://ec3o.fun/articles/VitePress%E5%BB%BA%E7%AB%99%E6%95%99%E7%A8%8B.html" target="_blank" rel="noreferrer">Ec3o的博客教程</a></p><p>AlbertZhang的博客教程:<a href="https://docs.bugdesigner.cn/docs/Tutorial/vitepress.html" target="_blank" rel="noreferrer">AlbertZhang的博客教程</a></p><p>AlberZhang的B站教学视频:<a href="https://www.bilibili.com/video/BV1XW4y1w7bc" target="_blank" rel="noreferrer">教学视频</a></p><p>本教程是上面所有教程的整合版，综合了各个教程的方案，亲测有效！</p>`,175),i=[e];function o(l,c,r,d,u,h){return p(),a("div",null,i)}const m=s(t,[["render",o]]);export{b as __pageData,m as default};
